import{_ as i,o as a,c as e,ae as t}from"./chunks/framework.RRduUuAx.js";const o="/assets/image-20230306004919274.BiPodcG_.png",r="/assets/image-20230306012043569.BF41rgYF.png",n="/assets/image-20230306013027095.CplDTRxJ.png",P="/assets/image-20230306013221307.BaVqUVUR.jpg",h="/assets/image-20230306214510029.DyxYPCal.png",k=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"szu/network/chapter-2.md","filePath":"szu/network/chapter-2.md"}'),s={name:"szu/network/chapter-2.md"};function u(c,l,d,T,m,b){return a(),e("div",null,[...l[0]||(l[0]=[t('<h2 id="_2-1-网络应用体系结构" tabindex="-1">2.1 网络应用体系结构 <a class="header-anchor" href="#_2-1-网络应用体系结构" aria-label="Permalink to &quot;2.1 网络应用体系结构&quot;">​</a></h2><p>三种体系结构</p><h3 id="c-s-结构" tabindex="-1">C/S 结构 <a class="header-anchor" href="#c-s-结构" aria-label="Permalink to &quot;C/S 结构&quot;">​</a></h3><ul><li>客户/服务器（C/S）结构，最基本最典型的网络应用结构</li><li>客户程序+服务器程序</li><li>主要特征 <ul><li>网路通信只在客户与服务器之间进行</li><li>客户之间相互不同信</li><li>客户端主动发起通信，服务器端被动接受通信</li></ul></li></ul><h3 id="p2p-结构" tabindex="-1">P2P 结构 <a class="header-anchor" href="#p2p-结构" aria-label="Permalink to &quot;P2P 结构&quot;">​</a></h3><ul><li>所有通信都是对等的通信方之间进行，没有客户与服务器之分，地位对等。</li><li>P2P 的每个对等端是客户与服务器的结合体</li><li>应用：文件分发、文件共享、视频流服务、BitTorent、Gnutella</li></ul><h3 id="混合结构" tabindex="-1">混合结构 <a class="header-anchor" href="#混合结构" aria-label="Permalink to &quot;混合结构&quot;">​</a></h3><ul><li>C/S 和 P2P 相结合，既有服务器的存在也有对等端客户的直接通信</li></ul><h2 id="_2-2-网络应用通信基本原理" tabindex="-1">2.2 网络应用通信基本原理 <a class="header-anchor" href="#_2-2-网络应用通信基本原理" aria-label="Permalink to &quot;2.2 网络应用通信基本原理&quot;">​</a></h2><ol><li>应用层通信过程：应用进程之间以 C/S 方式进行通信 <ul><li>服务器进程被动等待客户通信</li><li>客户进程主动发起通信</li></ul></li><li>在逻辑上，是两个应用层的进程直接交换数据，实际上应用层程序通过层间接口 API，往下传递数据给传输层，按照五层模型的方式来交换信息。<br><img src="'+o+'" alt="image-20230306004919274"></li><li>典型的网络应用编程接口：套接字（Socket） <ul><li>一个应用进程对多个传输层协议</li><li>每个协议对应一个接口，每个接口用一个 socket 进行绑定</li></ul></li><li>系统为每个套接字分配一个编号，就是端口号 port number <ul><li>服务器进程的端口号是特定的</li><li>客户进程的端口号是随机分配且唯一</li><li>例如 WEB 端口号 80</li></ul></li><li>应用层需要使用传输层的服务，传输层提供两种服务 <ul><li>TCP，面向连接，可靠，字节流传输服务</li><li>UDP，无连接，不可靠，数据报文传输服务</li></ul></li></ol><h2 id="_2-3-域名系统-dns" tabindex="-1">2.3 域名系统（DNS） <a class="header-anchor" href="#_2-3-域名系统-dns" aria-label="Permalink to &quot;2.3 域名系统（DNS）&quot;">​</a></h2><h3 id="ip-地址与域名" tabindex="-1">IP 地址与域名 <a class="header-anchor" href="#ip-地址与域名" aria-label="Permalink to &quot;IP 地址与域名&quot;">​</a></h3><ul><li>主机 IP 地址 <ul><li>为了确保通信时能相互识别，在 Internet 上的每台主机都必须有一个唯一的标识，即主机的 IP 地址。</li><li>在网络层，IP 协议就是根据 IP 地址实现信息传递的。</li><li>IP 地址由 32 位（即 4 字节）二进制数组成，通常书写时以四组十进制数字组成，并以点分隔，如：<code>172.16.254.1</code> 。</li></ul></li><li>普通用户不习惯记忆和使用 IP 地址，因此希望网络地址更加容易记忆，因此设计了域名，更加容易记忆。</li><li>域名系统就是：将域名和它的 IP 地址之间建立起一种映射关系 <ul><li>域名由多个分量组成， 各分量之间用“ .” 分隔开</li><li>各分量代表不同级别的域名</li><li>级别最低的域名在最左边， 级别最高的在最右边（ 顶级域名）</li><li>每一级域名由英文字母或数字组成<br> n 级域名.n-1 级域名. n-2 级域名………顶级域名</li></ul></li><li>域名结构 <img src="'+r+'" alt="image-20230306012043569"></li><li><code>**域名层次化域名空间**</code><ul><li>国家顶级域名： .cn \\ .us \\ uk</li><li>通用顶级域名： .com \\ .net \\ .gov \\ .edu</li><li>基础结构域名： arpa</li></ul></li></ul><h3 id="dns" tabindex="-1">DNS <a class="header-anchor" href="#dns" aria-label="Permalink to &quot;DNS&quot;">​</a></h3><ul><li>Internet 上的域名由域名系统 DNS(Domain Name System)统一管理</li><li>DNS 是一个分布式数据库系统， 包含三部分： <ul><li>域名空间</li><li>域名服务器</li><li>地址转换请求程序</li></ul></li><li>有了 DNS， 凡域名空间中有定义的域名可以有效地转换为对应的 IP 地址， 同样， IP 地址也可通过 DNS 转换成域名。</li><li>DNS 服务器的组织方式， 包含<code>四种类型的 DNS 服务器</code>： <ul><li>根域名服务器： 因特网上共有 13 个根 DNS 服务器；根域名服务器不做域名解析， 它知道所有顶级域服务器的 IP 地址。</li><li>顶级域名服务器</li><li>权威域名服务器</li><li>中间域名服务器</li><li>每台主机都会配置一个默认域名服务器， 即<em>本地域名服务器</em><img src="'+n+'" alt="image-20230306013027095"></li></ul></li></ul><h3 id="域名解析过程" tabindex="-1">域名解析过程 <a class="header-anchor" href="#域名解析过程" aria-label="Permalink to &quot;域名解析过程&quot;">​</a></h3><p><img src="'+P+'" alt="image-20230306013221307"></p><ul><li>本地域名服务器—&gt;根域名服务器—&gt;顶级域名服务器—&gt;权威域名服务器</li><li>递归查询， 每次查询由其他域名服务器转发查询</li><li>迭代查询， 每次查询由本地域名服务器和其他域名服务器直接对话</li><li>改进域名系统查询效率： 域名服务器增加缓存机制</li></ul><h2 id="_2-4-万维网" tabindex="-1">2.4 万维网 <a class="header-anchor" href="#_2-4-万维网" aria-label="Permalink to &quot;2.4 万维网&quot;">​</a></h2><h3 id="www" tabindex="-1">WWW <a class="header-anchor" href="#www" aria-label="Permalink to &quot;WWW&quot;">​</a></h3><ul><li>WWW 是 World Wide Web 的缩写， 也简称 Web， 从用户角度来看， Web 是由数量巨大且遍布全球的文档组成， 这些文档称为 Web 页（Web page） 。</li><li>万维网简称 Web 应用， 组成部分 <ul><li>Web 服务器</li><li>浏览器</li><li>超文本传输协议 HTTP</li></ul></li><li>URL <ul><li>URL 是为了在因特网上查询不同信息资源有统一的访问方法， 而定义的一种地址标识方法。</li><li>因特网上所有资源都有一个 URL 地址， 而且是独一无二的</li><li>URL 的完整格式： 主机域名+对象路径名 协议： //主机名或 IP 地址:端口号/路径名/文件名</li></ul></li></ul><h3 id="http" tabindex="-1">HTTP <a class="header-anchor" href="#http" aria-label="Permalink to &quot;HTTP&quot;">​</a></h3><ol><li>HTTP 协议 浏览器与 Web 服务器之间通信使用的协议， 规定了客户方与服务器方通信所使用的命令及响应。 <ul><li>HTTP1.0， 第一个广泛应用的版本</li><li>HTTP1.1， 目前 Web 应用最广泛的 HTTP 版本</li><li>HTTP2.0， 最新版本， 尚未广泛应用</li></ul></li><li>HTTP 连接 <ul><li>HTTP1.0，非持久连接</li><li>HTTP1.0，非持久+并行连接</li><li>HTTP1.1，非流水方式持久连接</li><li>HTTP1.1，流水方式持久连接 <img src="'+h+'" alt="image-20230306214510029"></li></ul></li><li>HTTP 报文 报文由 4 部分组成，起始行和空白行是不可缺少。<br> 报文类型：请求报文、响应报文 <ul><li>两种报文结构</li><li>两种报文的区别</li><li>HTTP 请求方法</li><li>HTTP 状态码表</li></ul></li></ol><h3 id="cookie" tabindex="-1">Cookie <a class="header-anchor" href="#cookie" aria-label="Permalink to &quot;Cookie&quot;">​</a></h3><ol><li>HTTP 是无状态协议， Web 应用引入 Cookie 机制跟踪用户</li><li>Cookie， 一种小型文本文件， 用于网络应用的身份识别、 会话跟踪等功能， 存储在用户本地终端。</li><li>Cookie 工作原理， 四类 Cookie 信息， 理解图 2.16 <ul><li>客户端 Cookie 信息（ 文本文件）</li><li>服务器端 Cookie 信息（ 数据库）</li><li>响应报文携带的 Cookie 信息</li><li>请求报文携带的 Cookie 信息</li></ul></li><li>Cookie 分类： 会话 Cookie、 永久 Cookie</li></ol><h2 id="_2-5-电子邮件" tabindex="-1">2.5 电子邮件 <a class="header-anchor" href="#_2-5-电子邮件" aria-label="Permalink to &quot;2.5 电子邮件&quot;">​</a></h2><h3 id="电子邮件系统结构" tabindex="-1">电子邮件系统结构 <a class="header-anchor" href="#电子邮件系统结构" aria-label="Permalink to &quot;电子邮件系统结构&quot;">​</a></h3><ul><li>邮件服务器</li><li>用户代理</li><li>简单邮件传输协议 SMTP</li><li>邮件读取协议</li></ul><h3 id="smtp" tabindex="-1">SMTP <a class="header-anchor" href="#smtp" aria-label="Permalink to &quot;SMTP&quot;">​</a></h3><p>SMIP 是 Internet 电子邮件中核心应用层协议，实现邮件服务器之间或用户代理到邮件服务器之间的邮件传输。SMIP 使用传输层 TCP 实现可靠数据传输。</p><h3 id="邮件格式与-mime" tabindex="-1">邮件格式与 MIME <a class="header-anchor" href="#邮件格式与-mime" aria-label="Permalink to &quot;邮件格式与 MIME&quot;">​</a></h3><p>多用途互联网邮件扩展（Multipurpose Internet Mail Extensions, MIME）。<br> 由于 SMIP 只能传输 7 位 ASCII 码文本内容，所以传输非 7 位的 ASCII 码文本时，必须依据一个标准将非 7 位转化为 7 位 ASCII 码文本。解决该问题的方案就是 MIME，目前已经广泛应用于互联网的邮件之中。</p><h3 id="邮件读取协议" tabindex="-1">邮件读取协议 <a class="header-anchor" href="#邮件读取协议" aria-label="Permalink to &quot;邮件读取协议&quot;">​</a></h3><p>由于 SMTP 是”推动“协议，不能用于读取邮件，当用户读取邮件时，所使用的应用层协议是邮件读取协议。<br> 目前 Internet 邮件系统中比较流行的邮件读取协议有第三版的邮局协议（Post Office Protocol-Version 3, POP3）、互联网邮件访问协议（Internet Mail Access Protocol, IMAP）和 HTTP，其中 HTTP 被用作 Web Mail 系统中的邮件读取协议。</p><ul><li>POP3</li><li>IMAP （收邮件协议）</li><li>HTTP</li></ul><h2 id="_2-6-ftp" tabindex="-1">2.6 FTP <a class="header-anchor" href="#_2-6-ftp" aria-label="Permalink to &quot;2.6 FTP&quot;">​</a></h2><p>文件传输协议（File Transfer Protocol, FTP）是在互联网的两个主机间实现文件互传的网络应用，其应用层协议也称为 FTP。</p><ul><li>使用 FTP 服务时，首先客户进程需要请求与 FTP 服务器的 21 号端口建立一条 TCP 连接，称为控制连接，然后开始 FTP 会话。</li><li>FTP 的显著特点是在传输文件内容时，需要新建一个数据连接。服务器进程用自己传送数据的熟知端口号（20）与客户进程所提供的端口号建立数据连接。</li></ul><h2 id="_2-7-p2p" tabindex="-1">2.7 P2P <a class="header-anchor" href="#_2-7-p2p" aria-label="Permalink to &quot;2.7 P2P&quot;">​</a></h2><p>P2P 应用：BitTorent、PPlive、Ppstream<br> P2P 在文件分发、文件共享等应用表现优异性能。</p><h2 id="_2-8-socket-编程基础" tabindex="-1">2.8 Socket 编程基础 <a class="header-anchor" href="#_2-8-socket-编程基础" aria-label="Permalink to &quot;2.8 Socket 编程基础&quot;">​</a></h2><ul><li>Internet 应用最广泛的互联网应用编程接口：Socket API</li><li>识记 Socket API 函数 <ul><li>创建套接字—int socket</li><li>绑定套接字——bind函数</li></ul></li><li>Socket API 调用过程</li></ul><h3 id="应用层常见协议与端口" tabindex="-1">应用层常见协议与端口 <a class="header-anchor" href="#应用层常见协议与端口" aria-label="Permalink to &quot;应用层常见协议与端口&quot;">​</a></h3><ul><li>DNS—53</li><li>HTTP-80</li><li>SMTP-25 / POP3-110</li><li>FTP 控制-21/FTP 数据-20</li></ul>',44)])])}const _=i(s,[["render",u]]);export{k as __pageData,_ as default};
